import{_ as t,c as a,o as r,ag as o}from"./chunks/framework.IQH0tUiJ.js";const g=JSON.parse('{"title":"Welcome to WebUI Framework","description":"","frontmatter":{"layout":"home","hero":{"name":"WebUI Framework","text":"Fast Web Rendering Without JavaScript Overhead","tagline":"Build UIs at compile time, serve them blazingly fast from any backend language","actions":[{"theme":"brand","text":"Get Started","link":"/guide/"},{"theme":"alt","text":"View on GitHub","link":"https://github.com/microsoft/webui"}]}},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),i={name:"index.md"};function n(s,e,l,d,c,h){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="welcome-to-webui-framework" tabindex="-1">Welcome to WebUI Framework <a class="header-anchor" href="#welcome-to-webui-framework" aria-label="Permalink to &quot;Welcome to WebUI Framework&quot;">​</a></h1><h2 id="a-new-approach-to-server-side-rendering" tabindex="-1">A New Approach to Server-Side Rendering <a class="header-anchor" href="#a-new-approach-to-server-side-rendering" aria-label="Permalink to &quot;A New Approach to Server-Side Rendering&quot;">​</a></h2><p>WebUI Framework is a high-performance solution for building web applications that deliver exceptional user experiences without JavaScript runtime overhead. Unlike traditional frameworks that build UIs at runtime, WebUI separates dynamic from static content at build time and creates an efficient protocol for fast rendering.</p><h3 id="why-webui" tabindex="-1">Why WebUI? <a class="header-anchor" href="#why-webui" aria-label="Permalink to &quot;Why WebUI?&quot;">​</a></h3><ul><li><strong>Language Agnostic Backend</strong>: Use Rust, Go, C#, PHP, Ruby, or any other language - no Node.js required!</li><li><strong>Optimized Web Vitals</strong>: Significantly faster FCP, LCP, and INP metrics compared to JS-based SSR</li><li><strong>Web Component-Based</strong>: Built on the native web platform using modern web components</li><li><strong>Edge-Ready</strong>: Can be served from edge functions or a streamable Service Worker</li><li><strong>Separation of Concerns</strong>: UI structure is cached and separate from state data</li><li><strong>Minimal Transfer Size</strong>: Only send the state, not the entire rendered HTML</li><li><strong>Framework Integration</strong>: Extensible plugin system for client-side hydration with frameworks like FAST-HTML</li></ul><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ol><li><strong>Build Time</strong>: WebUI discovers all your web components and creates a protocol that separates dynamic from static content</li><li><strong>Serving</strong>: Your backend (in any language) applies state to this protocol through a lightweight handler</li><li><strong>Rendering</strong>: Content reaches the browser pre-rendered and ready to display, with minimal JavaScript overhead</li></ol><p>Get started now by following our <a href="/guide/">installation guide</a> or check out the <a href="/tutorials/hello-world.html">Hello World tutorial</a>.</p>',8)])])}const u=t(i,[["render",n]]);export{g as __pageData,u as default};
